+fn mcp_error_to_cli_error(err: fastmcp::prelude::McpError) -> CliError {
+    match err.code {
+        McpErrorCode::InvalidParams | McpErrorCode::ResourceNotFound => {
+            CliError::InvalidArgument(err.message)
+        }
+        _ => CliError::Other(err.message),
+    }
+}
