+fn parse_tool_json_payload(tool_name: &str, payload: &str) -> CliResult<serde_json::Value> {
+    serde_json::from_str(payload).map_err(|error| {
+        CliError::Other(format!(
+            "local {tool_name} returned invalid JSON payload: {error}"
+        ))
+    })
+}
